import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    const f = e.target.files[0];
    setFile(f);
    setPreview(URL.createObjectURL(f));
  };

  const handlePredict = async () => {
    if (!file) return alert("Upload image");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);

    try {
      const res = await axios.post("http://localhost:5000/predict", formData);
      setResult(res.data);
    } catch (err) {
      console.error(err);
      alert("Error predicting");
    }

    setLoading(false);
  };

  return (
    <div className="container">
      <h1>🍇 Grape Disease Detection</h1>

      <div className="card">
        <input type="file" onChange={handleFileChange} />

        {preview && <img src={preview} alt="preview" />}

        <button onClick={handlePredict}>
          {loading ? "Predicting..." : "Predict"}
        </button>
      </div>

      {result && (
        <div className="result">
          <h2>Final Result</h2>
          <h3 className="highlight">{result.final_prediction}</h3>
          <p>
            Confidence: {(result.final_confidence * 100).toFixed(2)}%
          </p>
          <p>Best Model: {result.best_model}</p>

          <div className="models">
            {Object.entries(result.models).map(([name, data]) => (
              <div
                key={name}
                className={
                  name === result.best_model
                    ? "model best"
                    : "model"
                }
              >
                <h4>{name}</h4>
                <p>{data.prediction}</p>
                <p>{(data.confidence * 100).toFixed(2)}%</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
